import{_ as r,o as a,c as o,ah as t}from"./chunks/framework.DsjyFzT5.js";const f=JSON.parse('{"title":"网页性能优化","description":"","frontmatter":{"title":"网页性能优化","date":"2023-11-17T00:00:00.000Z","category":"FE","tags":["FE","performance"]},"headers":[],"relativePath":"_post/coding-summary/fe/web-performance.md","filePath":"_post/coding-summary/fe/web-performance.md"}'),l={name:"_post/coding-summary/fe/web-performance.md"};function i(c,e,d,n,s,h){return a(),o("div",null,[...e[0]||(e[0]=[t('<h1 id="网页性能优化" tabindex="-1">网页性能优化 <a class="header-anchor" href="#网页性能优化" aria-label="Permalink to &quot;网页性能优化&quot;">​</a></h1><h2 id="网页性能测试" tabindex="-1">网页性能测试 <a class="header-anchor" href="#网页性能测试" aria-label="Permalink to &quot;网页性能测试&quot;">​</a></h2><ul><li>使用 <a href="https://developer.chrome.com/docs/lighthouse/overview?hl=zh-cn" target="_blank" rel="noreferrer">Lighthouse</a> 测试</li></ul><h2 id="性能的一般注意事项" tabindex="-1">性能的一般注意事项 <a class="header-anchor" href="#性能的一般注意事项" aria-label="Permalink to &quot;性能的一般注意事项&quot;">​</a></h2><ol><li>减少重定向：即使是跨域重定向，也需要注意是否存在多次重定向，如： http =&gt; https、到站内又触发同源重定向等</li><li>缓存HTML响应 <ol><li>较短的生命周期，能减少请求数量，且确保能定期更新</li><li>使用<code>ETag</code>、<code>Last-modified</code>请求头，但是注意重新验证资源新鲜度本身也会消耗网络资源</li></ol></li></ol><blockquote><p>每当资源发生变化时，都必须生成新的 <code>ETag</code> 值。在后续请求中，浏览器会通过 <a href="https://developer.mozilla.org/docs/Web/HTTP/Headers/If-None-Match" target="_blank" rel="noreferrer"><code>If-None-Match</code> 请求标头</a>发送 <code>ETag</code> 值。如果服务器上的 <code>ETag</code> 与浏览器发送的资源匹配，服务器将做出 <code>304 Not Modified</code> 响应，浏览器将使用缓存中的资源。虽然这仍然会导致网络延迟，但 <code>304 Not Modified</code> 响应比整个 HTML 资源要小得多</p></blockquote><ol start="3"><li>衡量服务器响应时间：静态网页TTFB通常更低，但客户端提取数据的环境不可预测，最大限度地减少客户端工作量通常有助于提高以用户为中心的指标</li><li>压缩：压缩 HTML、JavaScript、CSS 和 SVG 图片，缩减通过网络传输的数据量。 <ol><li>尽可能使用 Brotli</li><li>文件大小至关重要</li><li>了解动态压缩与静态压缩</li></ol></li><li>内容分发网络（CDN）：<a href="https://web.dev/articles/content-delivery-networks?hl=zh-cn" target="_blank" rel="noreferrer">内容分发网络 (CDN)</a> 是一个分布式服务器网络，从您的源服务器缓存资源，进而从物理上距离用户更近的边缘服务器传送资源。由于靠近用户的物理位置可以缩短<a href="https://en.wikipedia.org/wiki/Round-trip_delay" target="_blank" rel="noreferrer">往返时间 (RTT)</a>，而 HTTP/2 或 HTTP/3、缓存和压缩等优化技术可让 CDN 更快地提供内容（与从源服务器提取内容相比）。在某些情况下，使用 CDN 可以显著改善您网站的 TTFB。</li></ol><h2 id="优化资源加载" tabindex="-1">优化资源加载 <a class="header-anchor" href="#优化资源加载" aria-label="Permalink to &quot;优化资源加载&quot;">​</a></h2><p>HTML资源中影响网页加载时间的一些概念：渲染阻塞、解析器屏蔽、预加载扫描程序。</p><p><strong>渲染阻塞</strong>： CSS 是一种阻塞渲染的资源，因为它会在构建 <a href="https://developer.mozilla.org/docs/Web/API/CSS_Object_Model" target="_blank" rel="noreferrer">CSS 对象模型 (CSSOM)</a> 之前阻止浏览器渲染任何内容。浏览器会阻止呈现，以防止出现<a href="https://en.wikipedia.org/wiki/Flash_of_unstyled_content" target="_blank" rel="noreferrer">无样式内容闪烁 (FOUC)</a>，这从用户体验的角度来看是不可取的。</p><p><strong>解析器屏蔽</strong>：解析器阻止资源会中断 HTML 解析器，例如没有 <code>async</code> 或 <code>defer</code> 属性的 <code>&lt;script&gt;</code> 元素。当解析器遇到 <code>&lt;script&gt;</code> 元素时，浏览器需要先评估并执行脚本，然后才能继续解析 HTML 的其余部分。这是特意设计的，因为在 DOM 构建过程中，脚本可能会修改或访问 DOM。</p><p><strong>预加载扫描程序</strong>：一种浏览器优化功能，它采用辅助 HTML 解析器的形式，可扫描原始 HTML 响应，以便先找到资源并进行推测性提取，然后再让主要 HTML 解析器发现这些资源。例如，预加载扫描程序允许浏览器开始下载 <code>&lt;img&gt;</code> 元素中指定的资源，即使在提取和处理 CSS 和 JavaScript 等资源时 HTML 解析器遭到阻止，也是如此。</p><p>为了充分利用预加载扫描器，关键资源应包含在服务器发送的 HTML 标记中。预加载扫描程序无法发现以下资源加载模式：</p><ul><li>由 CSS 使用 <code>background-image</code> 属性加载的图片。这些图片引用位于 CSS 中，并且预加载扫描器无法发现这些引用。</li><li>动态加载的脚本，采用 <code>&lt;script&gt;</code> 元素标记的形式，使用 JavaScript 或使用<a href="https://developer.mozilla.org/docs/Web/JavaScript/Reference/Operators/import" target="_blank" rel="noreferrer">动态 <code>import()</code></a> 加载的模块注入 DOM。</li><li>使用 JavaScript 在客户端上呈现的 HTML。此类标记包含在 JavaScript 资源的字符串中，预加载扫描程序无法发现此类标记。</li><li>CSS <code>@import</code> 声明。</li></ul><h3 id="css-优化" tabindex="-1">CSS 优化 <a class="header-anchor" href="#css-优化" aria-label="Permalink to &quot;CSS 优化&quot;">​</a></h3><ol><li>缩减CSS文件大小</li><li>移除未使用的CSS</li></ol><h2 id="参考资料" tabindex="-1">参考资料 <a class="header-anchor" href="#参考资料" aria-label="Permalink to &quot;参考资料&quot;">​</a></h2><p>[1] <a href="https://web.dev/learn/performance/welcome?hl=zh-cn" target="_blank" rel="noreferrer">web.dev “性能”课程</a></p>',18)])])}const g=r(l,[["render",i]]);export{f as __pageData,g as default};
